            print(k, 'kept=',v.get('kept'),'dropped=',v.get('dropped'),'in=',v.get('in') or v.get('total'))
elif isinstance(secs,list):
    for v in secs:
        print(v.get('title') or v.get('name'),'kept=',v.get('kept'),'dropped=',v.get('dropped'))
